import React, { useState, useEffect } from 'react';
import PatientTable from '../components/PatientTable';
import './patient.css';

const Patients = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [patients, setPatients] = useState([]); // State to hold DB data
    const [formData, setFormData] = useState({
        name: '',
        age: '',
        gender: 'Male',
        contact: ''
    });

    // 1. Fetch Patients from Backend on Load
    const fetchPatients = async () => {
        try {
            const response = await fetch('http://localhost:5000/api/patients');
            const data = await response.json();
            setPatients(data);
        } catch (error) {
            console.error("Error fetching patients:", error);
        }
    };

    useEffect(() => {
        fetchPatients();
    }, []);

    // 2. Handle Form Submission
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch('http://localhost:5000/api/patients', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData)
            });

            if (response.ok) {
                setIsModalOpen(false); // Close modal
                fetchPatients(); // Refresh the list
                setFormData({ name: '', age: '', gender: 'Male', contact: '' }); // Reset form
            }
        } catch (error) {
            console.error("Error saving patient:", error);
        }
    };

    return (
        <div className="patients-container">
            <div className="patients-header">
                <div>
                    <h1>Patient Directory</h1>
                    <p>Search and manage all hospital records.</p>
                </div>
                <button className="add-patient-btn" onClick={() => setIsModalOpen(true)}>
                    + New Registration
                </button>
            </div>

            <div className="management-bar">
                <div className="search-wrapper">
                    <span className="search-icon">🔍</span>
                    <input type="text" placeholder="Search by name, ID, or phone..." />
                </div>
            </div>

            <div className="table-section">
                {/* 3. Pass the dynamic data to your Table component */}
                <PatientTable patients={patients} />
            </div>

            {isModalOpen && (
                <div className="modal-backdrop">
                    <div className="modal-box">
                        <div className="modal-head">
                            <h2>Register Patient</h2>
                            <button className="close-x" onClick={() => setIsModalOpen(false)}>&times;</button>
                        </div>
                        <form className="registration-form" onSubmit={handleSubmit}>
                            <label>Full Name</label>
                            <input 
                                type="text" 
                                placeholder="Enter patient name" 
                                value={formData.name}
                                onChange={(e) => setFormData({...formData, name: e.target.value})}
                                required
                            />
                            
                            <div className="form-row">
                                <div className="input-half">
                                    <label>Age</label>
                                    <input 
                                        type="number" 
                                        value={formData.age}
                                        onChange={(e) => setFormData({...formData, age: e.target.value})}
                                        required
                                    />
                                </div>
                                <div className="input-half">
                                    <label>Gender</label>
                                    <select 
                                        value={formData.gender}
                                        onChange={(e) => setFormData({...formData, gender: e.target.value})}
                                    >
                                        <option>Male</option>
                                        <option>Female</option>
                                    </select>
                                </div>
                            </div>

                            <label>Contact Number</label>
                            <input 
                                type="tel" 
                                placeholder="+1..." 
                                value={formData.contact}
                                onChange={(e) => setFormData({...formData, contact: e.target.value})}
                                required
                            />

                            <button type="submit" className="submit-form-btn">Save to Database</button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Patients;
